def get_chat_html() -> str:
    return """<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>PRISM</title>
<style>
:root{--bg:#0f1117;--sf:#171b22;--br:rgba(255,255,255,.08);--tx:#ecf0f6;--mu:#9aa4b2;--ac:#5DCAA5;--rd:#E24B4A;--ye:#EF9F27;--bl:#3B8BD4}
@media (prefers-color-scheme: light){:root{--bg:#f5f7fb;--sf:#ffffff;--br:rgba(15,23,42,.12);--tx:#162030;--mu:#5b6778}}
*{box-sizing:border-box}html,body{height:100%}body{margin:0;background:var(--bg);color:var(--tx);font:14px/1.45 system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}
.app{display:grid;grid-template-columns:220px minmax(0,1fr);min-height:100vh}.sidebar{border-right:1px solid var(--br);background:var(--sf);padding:18px;display:flex;flex-direction:column;gap:18px}.brand{font-weight:800;letter-spacing:.1em}.group-title{font-size:11px;color:var(--mu);text-transform:uppercase;letter-spacing:.08em;margin:0 0 8px}.nav button,.identity button,.quick button,.send{appearance:none;border:1px solid var(--br);background:transparent;color:var(--tx);border-radius:12px;padding:10px 12px;text-align:left;cursor:pointer}.nav,.identity,.quick{display:grid;gap:8px}.status{margin-top:auto;padding:12px;border:1px solid var(--br);border-radius:14px;color:var(--mu)}.main{display:flex;flex-direction:column;min-width:0}.header{padding:18px 20px;border-bottom:1px solid var(--br);background:var(--sf);display:flex;justify-content:space-between;gap:12px;align-items:center}.messages{flex:1;overflow:auto;padding:20px;display:flex;flex-direction:column;gap:14px}.msg{max-width:860px}.msg.user{align-self:flex-end}.bubble,.card{border:1px solid var(--br);background:var(--sf);border-radius:16px;padding:14px 16px}.msg.user .bubble{background:rgba(59,139,212,.14)}.label{font-size:11px;color:var(--mu);margin:0 0 6px 4px}.card h3{margin:0 0 8px;font-size:15px}.sub{color:var(--mu)}.row{display:flex;gap:10px;align-items:center}.row+.row,.stack+.stack{margin-top:10px}.time{width:72px;color:var(--mu)}.bar{height:10px;border-radius:999px;background:rgba(255,255,255,.06);border:1px solid var(--br);overflow:hidden;flex:1}.fill{height:100%;background:linear-gradient(90deg,var(--ac),var(--bl))}.fill.warn{background:linear-gradient(90deg,var(--ye),var(--rd))}.pill{display:inline-block;padding:4px 8px;border-radius:999px;border:1px solid var(--br);font-size:11px;color:var(--mu);margin:8px 8px 0 0}.composer{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:12px;padding:16px 20px;border-top:1px solid var(--br);background:var(--sf)}textarea{width:100%;min-height:64px;max-height:180px;resize:vertical;border-radius:14px;border:1px solid var(--br);background:transparent;color:var(--tx);padding:12px 14px;font:inherit}.send{background:var(--ac);color:#082117;font-weight:700;padding:0 18px}.quick{padding:0 20px 16px}.muted{color:var(--mu)}
.tts-btn{appearance:none;border:1px solid var(--br);background:transparent;color:var(--mu);border-radius:10px;padding:6px 12px;cursor:pointer;font-size:12px;transition:color .15s,border-color .15s}.tts-btn.on{color:var(--ac);border-color:var(--ac)}
.notif-banner{display:none;padding:10px 20px;background:rgba(239,159,39,.1);border-bottom:1px solid rgba(239,159,39,.3);font-size:12px;color:var(--ye);gap:10px;align-items:flex-start;flex-direction:column}.notif-banner.visible{display:flex}.notif-item{display:flex;gap:8px;align-items:center;width:100%}.notif-item button{appearance:none;border:none;background:transparent;color:var(--mu);cursor:pointer;font-size:11px;margin-left:auto;padding:2px 6px}
@media (max-width:580px){.app{grid-template-columns:1fr}.sidebar{display:none}.composer{grid-template-columns:1fr}.messages,.header,.composer,.quick{padding-left:14px;padding-right:14px}}
</style>
</head>
<body>
<div class="app">
  <aside class="sidebar">
    <div class="brand">PRISM</div>
    <div>
      <p class="group-title">Modules</p>
      <div class="nav">
        <button data-mode="General">General</button>
        <button data-mode="Sport">Sport</button>
        <button data-mode="Medical">Medical</button>
        <button data-mode="Financial">Financial</button>
        <button data-mode="Legal">Legal</button>
        <button data-mode="Developer">Developer</button>
      </div>
    </div>
    <div>
      <p class="group-title">Identity</p>
      <div class="identity">
        <button data-demo="identity profile">Profile</button>
        <button data-demo="artifacts">Artifacts</button>
      </div>
    </div>
    <div class="status">Status: <span id="statusText">checking\u2026</span></div>
    <div id="perception-status" style="margin-top:6px;font-size:9.5px;color:var(--mu);padding:0 .3rem"></div>
  </aside>
  <main class="main">
    <div class="header">
      <div><strong>PRISM Chat</strong><div class="sub">Unified platform layer</div></div>
      <div style="display:flex;gap:10px;align-items:center">
        <button id="ttsBtn" class="tts-btn" title="Toggle text-to-speech">\ud83d\udd0a TTS</button>
        <div id="roleText" class="sub">offline</div>
      </div>
    </div>
    <div id="notifBanner" class="notif-banner"></div>
    <div id="messages" class="messages"></div>
    <div class="quick" id="quick"></div>
    <form class="composer" id="composer">
      <textarea id="message" placeholder="Ask PRISM anything\u2026"></textarea>
      <button class="send" type="submit">Send</button>
    </form>
  </main>
</div>
<script>
const API='http://127.0.0.1:8742';
const state={mode:'General',ttsOn:false};
const messages=document.getElementById('messages');
const quick=document.getElementById('quick');
const input=document.getElementById('message');
const statusText=document.getElementById('statusText');
const roleText=document.getElementById('roleText');
const ttsBtn=document.getElementById('ttsBtn');
const notifBanner=document.getElementById('notifBanner');
const quickPrompts=['Plan my day','Help me plan: run a marathon in 6 months','How do I get my first 100 customers?','Predict City vs Arsenal','Show squad risk','Medical triage','Portfolio invest','Identity profile','Log wearables: HRV 58ms, sleep 7hrs',"What's my current context?"];
function esc(value){return String(value==null?'':value).replace(/[&<>"]/g,function(ch){return({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'})[ch];});}
function pct(value){const n=Number(value);if(!Number.isFinite(n))return 0;return Math.max(0,Math.min(100,Math.round((n<=1?n*100:n))));}
function bubble(role,html){const wrap=document.createElement('div');wrap.className='msg '+role;wrap.innerHTML='<div class="label">'+(role==='user'?'You':'PRISM')+'</div>'+html;messages.appendChild(wrap);messages.scrollTop=messages.scrollHeight;}
function renderCard(card){card=card||{type:'text',body:''};const data=card.data||{};if(card.type==='plan'){return '<div class="card"><h3>'+esc(card.title||'Daily Plan')+'</h3>'+(data.tasks||[]).map(function(task){return '<div class="row"><div class="time">'+esc(task.time||'')+'</div><div>'+esc(task.title||task.category||'Task')+'</div></div>';}).join('')+'<div class="pill">'+esc(data.primary_focus||'')+'</div></div>';}if(card.type==='prediction'){return '<div class="card"><h3>'+esc(card.title||'Match Prediction')+'</h3><div class="stack"><div>'+esc(data.home||'Home')+' vs '+esc(data.away||'Away')+'</div><div class="row"><span>Home</span><div class="bar"><div class="fill" style="width:'+pct(data.p_home)+'%"></div></div><strong>'+pct(data.p_home)+'%</strong></div><div class="row"><span>Draw</span><div class="bar"><div class="fill" style="width:'+pct(data.p_draw)+'%"></div></div><strong>'+pct(data.p_draw)+'%</strong></div><div class="row"><span>Away</span><div class="bar"><div class="fill warn" style="width:'+pct(data.p_away)+'%"></div></div><strong>'+pct(data.p_away)+'%</strong></div></div></div>';}if(card.type==='squad'){return '<div class="card"><h3>'+esc(card.title||'Squad Risk Overview')+'</h3>'+(data.players||[]).map(function(player){return '<div class="row"><span>'+esc(player.name)+'</span><div class="bar"><div class="fill warn" style="width:'+pct(player.confidence)+'%"></div></div><span>'+esc(player.risk_level)+'</span></div>';}).join('')+'</div>';}if(card.type==='domain'){return '<div class="card"><h3>'+esc(card.title||'Domain Recommendation')+'</h3><div class="sub">'+esc(data.recommended||'')+'</div>'+(data.options||[]).map(function(option){return '<div class="row"><span>'+esc(option.name)+'</span><div class="bar"><div class="fill" style="width:'+pct(option.activation)+'%"></div></div><strong>'+pct(option.activation)+'%</strong></div>';}).join('')+'</div>';}if(card.type==='identity'){return '<div class="card"><h3>'+esc(card.title||'Your Decision Profile')+'</h3>'+(data.domains||[]).map(function(domain){return '<div class="row"><span>'+esc(domain.label)+'</span><div class="bar"><div class="fill" style="width:'+pct(domain.value)+'%"></div></div><span>'+esc(domain.crystallised?'set':'emerging')+'</span></div>';}).join('')+'<div class="sub">'+esc(data.insight||'')+'</div></div>';}if(card.type==='plan'&&data.strategies){const strats=data.strategies||[];const top=strats[0]||{};const bd='<div class="label">PRISM</div>';const stepRows=(top.steps||[]).slice(0,4).map(function(s){return '<div class="si"><div class="st">'+esc(s.timeline||'')+'</div><div class="sd" style="background:var(--ac)"></div><div class="stx">'+esc(s.action)+'</div></div>';}).join('');const altRows=strats.slice(1,4).map(function(s,i){return '<div class="br"><div class="bl">Alt '+(i+1)+': '+esc(s.name)+'</div><div class="bt"><div class="bf" style="width:'+(s.activation*100).toFixed(0)+'%;background:var(--mu);opacity:.6"></div></div><div class="bp">'+(s.activation*100).toFixed(0)+'%</div></div>';}).join('');return bd+'<div class="card"><div class="card-t">\u2605 '+esc(top.name||'Optimal strategy')+' <span style="font-size:10px;opacity:.5">('+((top.activation||0)*100).toFixed(0)+'%)</span></div>'+stepRows+altRows+'<div class="meta">Domain <b>'+esc(data.domain||'')+'</b> \u00b7 Timeline <b>'+esc(data.timeline||'')+'</b> \u00b7 Fulcrum <b>'+(data.fulcrum||0).toFixed(3)+'</b></div></div>';}if(card.type==='approval'){const d=card.data||{};const bd='<div class="label">PRISM</div>';return bd+'<div class="card" style="border-color:var(--ye)"><div class="card-t" style="color:var(--ye)">\u26a0 '+esc(card.title)+'</div><p style="font-size:11px;margin-bottom:.5rem">'+esc(card.body)+'</p><div style="display:flex;gap:8px"><button onclick="approveTask('+esc(JSON.stringify(d))+',\'approve\')" style="flex:1;padding:6px;border-radius:6px;background:var(--ac);border:none;cursor:pointer;font-size:11px;color:#fff;font-family:inherit">Approve</button><button onclick="approveTask('+esc(JSON.stringify(d))+',\'deny\')" style="flex:1;padding:6px;border-radius:6px;background:var(--sf);border:.5px solid var(--br);cursor:pointer;font-size:11px;color:var(--tx);font-family:inherit">Deny</button></div></div>';}return '<div class="card"><h3>'+esc(card.title||'PRISM')+'</h3><div>'+String(card.body||'')+'</div></div>';}
async function approveTask(data,decision){const d=data||{};bubble('user','<div class="bubble">'+esc(decision==='approve'?'Approved':'Denied')+'</div>');bubble('agent','<div class="card"><div class="label">PRISM</div><span class="muted">Processing\u2026</span></div>');let card;try{const r=await fetch(API+'/device/approve',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({task:d.task||'',params:d.params||{},approved:decision==='approve'}),signal:AbortSignal.timeout(15000)});if(r.ok)card=await r.json();else throw new Error();}catch{card={type:'text',title:'',body:'Could not process approval.',data:{},actions:[]};}const msgs=document.querySelectorAll('.msg');if(msgs.length)msgs[msgs.length-1].remove();bubble('agent',renderCard(card));}
function demo(msg){const text=String(msg||'').toLowerCase();if(/plan|day|morning/.test(text)){return {type:'plan',title:'Daily Plan',body:'',data:{primary_focus:'Recovery',tasks:[{time:'07:00',category:'prep',title:'Mobility primer',duration:20},{time:'09:00',category:'focus',title:'Deep work block',duration:90},{time:'13:00',category:'review',title:'Film review',duration:45},{time:'17:00',category:'reset',title:'Recovery walk',duration:30}]}};}if(/predict|match|vs/.test(text)){return {type:'prediction',title:'Match Prediction',body:'',data:{home:'City',away:'Arsenal',p_home:0.46,p_draw:0.26,p_away:0.28,predicted:'City',confidence:0.68}};}if(/injury|risk|squad/.test(text)){return {type:'squad',title:'Squad Risk Overview',body:'',data:{players:[{name:'Player A',risk_level:'high',confidence:0.82},{name:'Player B',risk_level:'medium',confidence:0.61},{name:'Player C',risk_level:'low',confidence:0.24}]}};}if(/identity|profile/.test(text)){return {type:'identity',title:'Your Decision Profile',body:'',data:{domains:[{label:'Medical',value:0.74,crystallised:true},{label:'Financial',value:0.43,crystallised:true},{label:'Sport',value:0.58,crystallised:false},{label:'Developer',value:0.36,crystallised:false}],insight:'Pattern still crystallising',confidence:0.63,n_decisions:12}};}if(/triage|medical/.test(text)){return {type:'domain',title:'Medical Recommendation',body:'',data:{domain:'Medical',recommended:'Urgent_GP',confidence:0.78,fulcrum:0.61,options:[{name:'GP',activation:0.42},{name:'Urgent_GP',activation:0.78},{name:'AE_4hr',activation:0.57}]}};}if(/portfolio|invest/.test(text)){return {type:'domain',title:'Financial Recommendation',body:'',data:{domain:'Financial',recommended:'Mod_balanced',confidence:0.74,fulcrum:0.49,options:[{name:'Gov_bonds',activation:0.31},{name:'Mod_balanced',activation:0.74},{name:'Growth',activation:0.52}]}};}return {type:'text',title:'PRISM',body:'Try: plan my day, predict City vs Arsenal, squad risk, identity profile, medical triage, or portfolio invest.',data:{}};}
async function send(override){const message=(override!=null?override:input.value).trim();if(!message)return;bubble('user','<div class="bubble">'+esc(message)+'</div>');input.value='';try{const response=await fetch(API+'/chat',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({message:message,mode:state.mode})});if(!response.ok)throw new Error('offline');bubble('agent',renderCard(await response.json()));}catch(error){bubble('agent',renderCard(demo(message)));}}
function renderQuick(){quick.innerHTML=quickPrompts.map(function(prompt){return '<button type="button" data-prompt="'+esc(prompt)+'">'+esc(prompt)+'</button>';}).join('');}
async function toggleTTS(){try{const r=await fetch(API+'/tts',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'toggle'}),signal:AbortSignal.timeout(2000)});if(r.ok){const d=await r.json();state.ttsOn=d.enabled;}}catch{state.ttsOn=!state.ttsOn;}ttsBtn.classList.toggle('on',state.ttsOn);ttsBtn.title=state.ttsOn?'TTS on \u2014 click to disable':'TTS off \u2014 click to enable';}
function dismissNotif(triggerId,el){el.closest('.notif-item').remove();if(!notifBanner.querySelector('.notif-item'))notifBanner.classList.remove('visible');try{fetch(API+'/tts',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'speak',text:''}),signal:AbortSignal.timeout(1000)}).catch(function(){});}catch{}}
async function pollProactive(){try{const r=await fetch(API+'/proactive?n=5',{signal:AbortSignal.timeout(2000)});if(!r.ok)return;const d=await r.json();const events=d.events||[];if(!events.length){notifBanner.classList.remove('visible');return;}notifBanner.innerHTML='';events.forEach(function(e){const item=document.createElement('div');item.className='notif-item';item.innerHTML='<span>\u26a0\ufe0f '+esc(e.message)+'</span><button onclick="dismissNotif(\''+esc(e.trigger_id)+'\',this)" title="Dismiss">\u2715</button>';notifBanner.appendChild(item);});notifBanner.classList.add('visible');}catch{}}
ttsBtn.addEventListener('click',toggleTTS);
document.getElementById('composer').addEventListener('submit',function(event){event.preventDefault();send();});
document.body.addEventListener('click',function(event){const prompt=event.target.getAttribute('data-prompt');const mode=event.target.getAttribute('data-mode');const demoPrompt=event.target.getAttribute('data-demo');if(prompt)send(prompt);if(demoPrompt)send(demoPrompt);if(mode)state.mode=mode;});
(function(){const controller=new AbortController();const timer=setTimeout(function(){controller.abort();},1500);fetch(API+'/status',{signal:controller.signal}).then(function(response){return response.json();}).then(function(data){clearTimeout(timer);const ollamaStr=data.ollama?('Ollama: '+(data.ollama_model||'running')+' \u2713'):'Ollama: not running';statusText.textContent='connected \u00b7 '+ollamaStr;roleText.textContent=data.role||'connected';}).catch(function(){clearTimeout(timer);statusText.textContent='Server offline (demo mode)';roleText.textContent='demo';});renderQuick();try{fetch(API+'/perception/status',{signal:AbortSignal.timeout(1500)}).then(function(pr){if(pr.ok)return pr.json();}).then(function(p){if(!p)return;const el=document.getElementById('perception-status');if(p.active_channels&&p.active_channels.length){el.textContent='Sensing: '+p.active_channels.join(' \u00b7 ');if(p.summary&&p.summary!=='normal context')el.textContent+=' \u00b7 '+p.summary;}}).catch(function(){});}catch(e){}setInterval(pollProactive,30000);setTimeout(pollProactive,2000);setTimeout(async function(){let capStr='';let perceptStr='';try{const[capR,perR]=await Promise.all([fetch(API+'/device/capabilities',{signal:AbortSignal.timeout(1500)}),fetch(API+'/perception/status',{signal:AbortSignal.timeout(1500)}),]);if(capR.ok){const d=await capR.json();const cats=Object.keys(d.categories||{}).slice(0,5);if(cats.length)capStr='<br><span style="font-size:10.5px;color:var(--mu)">Device: '+cats.join(' \u00b7 ')+'</span>';}if(perR.ok){const p=await perR.json();if(p.summary&&p.summary!=='normal context')perceptStr='<br><span style="font-size:10.5px;color:var(--ac)">Context: '+p.summary+'</span>';}}catch{}bubble('agent',renderCard({type:'text',title:'PRISM',body:'Hello \ud83d\udc4b I\'m PRISM \u2014 your decision intelligence.<br><br>I decide, plan, and execute \u2014 for any task, in any domain.'+capStr+perceptStr+'<br><br>What would you like to do today?',data:{}}));},250);})();
</script>
</body>
</html>"""
